    { id: 'D19', name: 'Dr. Kiran Patel', specialty: 'Infectious Disease', location: 'Infectious Disease Center', timing: '9:00 AM - 1:00 PM', status: 'Busy', experience: '15 years' },
    { id: 'D20', name: 'Dr. Anil Kumar', specialty: 'Emergency Medicine', location: 'Emergency Department', timing: '24/7 On-Call', status: 'Available', experience: '10 years' },
    { id: 'D21', name: 'Dr. Swati Agarwal', specialty: 'Anesthesiology', location: 'Surgery Center', timing: '6:00 AM - 2:00 PM', status: 'Available', experience: '16 years' },
    { id: 'D22', name: 'Dr. Harish Chandra', specialty: 'Radiology', location: 'Imaging Center', timing: '8:00 AM - 5:00 PM', status: 'Available', experience: '21 years' },
    { id: 'D23', name: 'Dr. Nisha Aggarwal', specialty: 'Pathology', location: 'Diagnostic Lab', timing: '7:30 AM - 3:30 PM', status: 'Available', experience: '13 years' }
  ];

  const specialties = [
    'All Specialties',
    'Cardiology',
    'Pediatrics', 
    'General Medicine',
    'Gynecology',
    'Orthopedic',
    'Dermatology',
    'ENT',
    'Ophthalmology',
    'Neurology',
    'Psychiatry',
    'Urology',
    'Endocrinology',
    'Gastroenterology',
    'Rheumatology',
    'Oncology',
    'Pulmonology',
    'Nephrology',
    'Hematology',
    'Infectious Disease',
    'Emergency Medicine',
    'Anesthesiology',
    'Radiology',
    'Pathology'
  ];

  // Filter doctors based on search and specialty
  const filteredDoctors = doctorsData.filter(doctor => {
    const matchesSearch = doctor.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         doctor.specialty.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         doctor.location.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesSpecialty = selectedSpecialty === '' || selectedSpecialty === 'All Specialties' || doctor.specialty === selectedSpecialty;
    return matchesSearch && matchesSpecialty;
  });

  const handleBookAppointment = (doctor) => {
    navigate('/appointments', { state: { selectedDoctor: doctor } });
  };

  return (
    <div className="min-h-screen bg-bg-secondary">
      {/* Header - Match Medicines theme */}
      <div className="bg-gradient-to-r from-primary-color to-primary-dark text-white py-12">
        <div className="container mx-auto px-6 text-center">
          <h1 className="text-4xl font-black mb-2 tracking-tight">
            Doctor <span className="text-primary-light">Availability</span>
          </h1>
          <p className="text-primary-light">View schedules and book appointments with available doctors</p>
        </div>
      </div>

      <div className="container mx-auto px-6 py-8 pb-40">
        {/* Search and Filter */}
        <div className="card-elevated mb-6 max-w-5xl mx-auto">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Search */}
            <div>
              <label htmlFor="doctor-search" className="block text-sm font-semibold text-text-primary mb-1">Search doctors</label>
              <div className="input-wrapper">
                <input
                  id="doctor-search"
                  type="text"
                  placeholder="Search by name, specialty, or location..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="input"
                  autoComplete="off"
                />
                {searchTerm && (
                  <button
                    type="button"
                    aria-label="Clear search"
                    className="input-clear-btn"
                    onClick={() => setSearchTerm('')}
                  >
                    ×
                  </button>
                )}
              </div>
            </div>

            {/* Specialty Filter */}
            <div>
              <label className="block text-sm font-semibold text-text-primary mb-1">Filter by specialty</label>
              <select
                value={selectedSpecialty}
                onChange={(e) => setSelectedSpecialty(e.target.value)}
                className="input"
              >
                {specialties.map(specialty => (
                  <option key={specialty} value={specialty}>
                    {specialty}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Doctors Table */}
        <div className="card-elevated overflow-hidden">
          <div className="overflow-x-auto">
            <table className="inventory-table sticky-header w-full table-fixed text-sm">
              <colgroup>
                <col className="col-doctor-name" />
                <col className="col-specialty" />
                <col className="col-timing" />
                <col className="col-status" />
                <col className="col-book" />
              </colgroup>
              <thead>
                <tr>
                  <th className="text-left p-3 text-sm font-semibold text-text-primary">Doctor</th>
                  <th className="text-left p-3 text-sm font-semibold text-text-primary">Specialty</th>
                  <th className="text-center p-3 text-sm font-semibold text-text-primary nowrap">Timing</th>
                  <th className="text-center p-3 text-sm font-semibold text-text-primary nowrap">Status</th>
                  <th className="text-center p-3 text-sm font-semibold text-text-primary nowrap">Book</th>
                </tr>
              </thead>
              <tbody>
                {filteredDoctors.map((doctor) => (
                  <tr key={doctor.id} className="hover:bg-gray-50">
                    <td className="p-3 align-top break-words" data-label="Doctor">
                      <div className="font-medium text-text-primary leading-snug">{doctor.name}</div>
                      <div className="text-xs text-text-secondary mt-0.5 leading-tight">{doctor.location}</div>
                      <div className="text-xs text-text-muted mt-0.5">{doctor.experience} exp</div>
                    </td>
                    <td className="p-3 align-top" data-label="Specialty">
                      <div className="text-text-primary font-medium">{doctor.specialty}</div>
                    </td>
                    <td className="p-3 text-center align-top" data-label="Timing">
                      <span className="text-xs text-text-secondary">{doctor.timing}</span>
                    </td>
                    <td className="p-3 text-center align-top" data-label="Status">
                      <span className={`text-xs font-medium px-2 py-1 rounded-full ${
                        doctor.status === 'Available' 
                          ? 'bg-green-100 text-green-700' 
                          : 'bg-red-100 text-red-700'
                      }`}>
                        {doctor.status}
                      </span>
                    </td>
                    <td className="p-3 text-center align-top" data-label="Book">
                      <button
                        onClick={() => handleBookAppointment(doctor)}
                        disabled={doctor.status !== 'Available'}
                        className={`btn btn-sm ${
                          doctor.status === 'Available' 
                            ? 'btn-primary' 
                            : 'btn-outline opacity-50 cursor-not-allowed'
                        }`}
                      >
                        {doctor.status === 'Available' ? 'Book' : 'Busy'}
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Results Summary / Empty State */}
        {filteredDoctors.length === 0 && (
          <div className="text-center py-12 text-text-secondary">No doctors found</div>
        )}
        {filteredDoctors.length > 0 && (
          <div className="mt-6 text-center text-text-secondary text-sm">
            Showing {filteredDoctors.length} of {doctorsData.length} doctors
          </div>
        )}
      </div>
    </div>
  );
};

export default Availability;
